class WebSocketCodecTest {

    private fun decode(codec: TextFrameCodec, vararg chunks: String): List<String> {
        val out = mutableListOf<String>()
        for (c in chunks) codec.decode(c, out)
        return out
    }

    @Test
    fun textCodecPassesChunkThroughVerbatim() {
        assertEquals(listOf("hello"), decode(TextFrameCodec(), "hello"))
    }

    @Test
    fun textCodecEmitsEachChunkSeparately() {
        assertEquals(listOf("foo", "bar"), decode(TextFrameCodec(), "foo", "bar"))
    }

    @Test
    fun textCodecPassesRawTtyBytesThrough() {
        // ANSI escape sequences are common in PTY output.
        assertEquals(listOf("\u001b[Kprompt"), decode(TextFrameCodec(), "\u001b[Kprompt"))
    }

    @Test
    fun textCodecIgnoresEmptyChunks() {
        assertTrue(decode(TextFrameCodec(), "").isEmpty())
    }

    @Test
    fun textCodecReturnsEmptyWhenNoChunksArrived() {
        assertTrue(decode(TextFrameCodec()).isEmpty())
    }

    @Test
    fun textCodecPreservesBytesThatContainColons() {
        // Even strings that LOOK like a frame are passed through verbatim
        // — the wire never delivers them in this direction.
        assertEquals(listOf("0:5:a:b:c"), decode(TextFrameCodec(), "0:5:a:b:c"))
    }

    @Test
    fun textCodecEncodeProducesDataFrameFormat() {
        assertEquals("0:5:hello\n", TextFrameCodec().encode("hello"))
    }

    @Test
    fun textCodecEncodeResizeProducesResizeFrameFormat() {
        assertEquals("1:120:32:", TextFrameCodec.encodeResize(120, 32))
