        val out = mutableListOf<ByteArray>()
        codec.decodeBinary(byteArrayOf(1, 2, 3, 4, 5), out)
        assertEquals(1, out.size)
        assertEquals(listOf<Byte>(1, 2, 3, 4, 5), out[0].toList())
